                <EmptyState
                  icon={Video}
                  title="لا توجد فيديوهات"
                  description="سيتم عرض فيديوهات المشروع هنا"
                  className="py-8"
                />
              )}
            </div>
          </DashboardCard>
        </div>

        {/* Timeline */}
        <div className="space-y-6">
          <DashboardCard className="p-6">
            <SectionTitle title="السجل الزمني" />
            <ProjectTimeline events={timeline} />
          </DashboardCard>
        </div>
      </div>
    </div>
  );
}

