        <link rel="manifest" href="/manifest.json" />
      </head>
      <body
        className={`${cairo.variable} ${inter.variable} font-sans antialiased`}
      >
        <ThemeProvider
          attribute="class"
          defaultTheme="dark"
          enableSystem
          disableTransitionOnChange
